import java.util.Scanner;

public class SecureBufferUsage {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Ensure the input size does not exceed a certain limit
        if (name.length() > 10) {
            System.out.println("Input size exceeds the limit of 10 characters.");
            return;
        }

        // Copy input string into a buffer of appropriate size
        char[] buffer = new char[name.length()];
        name.getChars(0, name.length(), buffer, 0);

        System.out.println("Welcome, " + new String(buffer));
    }
}

